import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        while (true) {
            Integer nObj = fs.nextInt();
            if (nObj == null) break;
            int N = nObj;
            int M = fs.nextInt();
            int[] rowMax = new int[N];
            int[] colMin = new int[M];
            Arrays.fill(rowMax, Integer.MIN_VALUE);
            Arrays.fill(colMin, Integer.MAX_VALUE);
            int[][] a = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    a[i][j] = fs.nextInt();
                    rowMax[i] = Math.max(rowMax[i], a[i][j]);
                    colMin[j] = Math.min(colMin[j], a[i][j]);
                }
            }
            boolean ok = false;
            outer:
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if (a[i][j] == rowMax[i] && a[i][j] == colMin[j]) {
                        ok = true;
                        break outer;
                    }
                }
            }
            out.append(ok ? "Yes" : "No").append('\n');
        }
        System.out.print(out.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        Integer nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); if (c == -1) return null; } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

