#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    idx = 0
    out_lines = []
    while idx < len(data):
        N = data[idx]; M = data[idx+1]; idx += 2
        row_max = [-10**9]*N
        col_min = [10**9]*M
        matrix = []
        for i in range(N):
            row = data[idx:idx+M]
            idx += M
            matrix.append(row)
            for j, val in enumerate(row):
                if val > row_max[i]:
                    row_max[i] = val
                if val < col_min[j]:
                    col_min[j] = val
        ok = False
        for i in range(N):
            for j in range(M):
                if matrix[i][j] == row_max[i] and matrix[i][j] == col_min[j]:
                    ok = True
                    break
            if ok:
                break
        out_lines.append('Yes' if ok else 'No')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

